class TransactionProcessor {
    private final Map<String, BigDecimal> balances = new ConcurrentHashMap<>();

    public TransactionProcessor() {
        balances.put("ACC1001", new BigDecimal("100000.00"));
        balances.put("ACC2001", new BigDecimal("50000.00"));
    }

    public synchronized TransactionResponse process(TransactionRequest request) throws BankingFault {
        if (request.transactionId == null || request.transactionId.isEmpty()) {
            throw new BankingFault("Missing transactionId");
        }
        if (request.fromAccount == null || request.toAccount == null || request.amount == null || request.currency == null) {
            throw new BankingFault("Missing required fields");
        }
        if (request.amount.signum() <= 0) {
            throw new BankingFault("Amount must be positive");
        }
        BigDecimal fromBalance = balances.getOrDefault(request.fromAccount, BigDecimal.ZERO);
        if (fromBalance.compareTo(request.amount) < 0) {
            return new TransactionResponse(request.transactionId, "DECLINED", "Insufficient funds", fromBalance);
        }
        BigDecimal toBalance = balances.getOrDefault(request.toAccount, BigDecimal.ZERO);
        fromBalance = fromBalance.subtract(request.amount);
        toBalance = toBalance.add(request.amount);
        balances.put(request.fromAccount, fromBalance);
        balances.put(request.toAccount, toBalance);
        return new TransactionResponse(request.transactionId, "APPROVED", "Transaction completed", fromBalance);
    }
}

